import React, { useState } from 'react';

function Login({ onLogin }) {
  const [usuario, setUsuario] = useState('');
  const [senha, setSenha] = useState('');
  const [mensagem, setMensagem] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();

    // Garante que ambos estejam preenchidos
    if (!usuario.trim() || !senha.trim()) {
      setMensagem("Preencha usuário e senha.");
      return;
    }

    // Passa as credenciais brutas para o wrapper
    onLogin({ usuario: usuario.trim(), senha: senha.trim() });
  };

  return (
    <form
      onSubmit={handleSubmit}
      className="max-w-sm mx-auto p-6 bg-white rounded-2xl shadow space-y-4 mt-12"
    >
      <h2 className="text-2xl font-bold mb-4">Login</h2>

      <input
        className="w-full border rounded px-3 py-2"
        placeholder="Usuário"
        value={usuario}
        onChange={e => setUsuario(e.target.value)}
        required
      />

      <input
        className="w-full border rounded px-3 py-2"
        placeholder="Senha"
        type="password"
        value={senha}
        onChange={e => setSenha(e.target.value)}
        required
      />

      <button
        className="w-full bg-[#3172C0] text-white py-2 rounded-full font-semibold"
        type="submit"
      >
        Entrar
      </button>

      {mensagem && <p className="text-red-600">{mensagem}</p>}
    </form>
  );
}

export default Login;
